public class AdjacencyList {

    private Map<Integer, List<int[]>> adj = new HashMap<>();

    public void addVertex(int v) {
        adj.putIfAbsent(v, new ArrayList<>());
    }

    public void addEdge(int from, int to, int weight) {
        addVertex(from); addVertex(to);
        // TODO: add {to, weight} to adj.get(from)
    }

    public List<int[]> getNeighbors(int v) {
        return adj.getOrDefault(v, Collections.emptyList());
    }

    public void printEdges() {
        for (int v : new TreeSet<>(adj.keySet())) {
            for (int[] edge : adj.get(v)) {
                System.out.println(v + " -> " + edge[0] + " (weight=" + edge[1] + ")");
            }
        }
    }

    public static void main(String[] args) {
        AdjacencyList g = new AdjacencyList();
        g.addEdge(0, 1, 4); g.addEdge(0, 2, 2);
        g.addEdge(1, 3, 5); g.addEdge(2, 3, 1);
        g.printEdges();
        System.out.println("Neighbors of 0: " + g.getNeighbors(0).size());
    }
}

